defmodule AdminDashboardWeb.Admin.UserController do
  use AdminDashboardWeb, :controller

  alias AdminDashboard.Accounts.UserQueries

  def index(conn, params) do
    search = Map.get(params, "search", "")
    role = Map.get(params, "role", "all")
    page = params |> Map.get("page", "1") |> String.to_integer()

    case UserQueries.search_users(search, role, page) do
      {:ok, result} ->
        conn
        |> put_status(200)
        |> json(%{
          users: result.users,
          meta: %{
            total: result.total,
            page: result.page,
            per_page: result.per_page,
            total_pages: result.total_pages
          }
        })

      {:error, _reason} ->
        conn
        |> put_status(500)
        |> json(%{error: "Failed to fetch users"})
    end
  end

  def stats(conn, _params) do
    case UserQueries.user_stats() do
      {:ok, stats} ->
        json(conn, %{stats: stats})

      {:error, _reason} ->
        conn
        |> put_status(500)
        |> json(%{error: "Failed to fetch stats"})
    end
  end

  def filter(conn, %{"filters" => filters}) when is_map(filters) do
    case UserQueries.filter_users(filters) do
      {:ok, users} ->
        json(conn, %{users: users})

      {:error, _reason} ->
        conn
        |> put_status(500)
        |> json(%{error: "Failed to filter users"})
    end
  end
end